import React, { useState, useEffect } from "react";
import { useNavigate, Link } from "react-router-dom";
import { Image, Form} from 'react-bootstrap'
import MainLayout from "../../components/Layout";
import BASE_URL from "../../config";
import DatePicker from "react-datepicker";
import "react-datepicker/dist/react-datepicker.css";
import $ from 'jquery';
import * as bootstrap from "bootstrap";
import SummaryCard from "../../components/SummaryCard";
import CommonTable from "../../components/CommonTable";
import CommonInstructions from "../../components/CommonInstructions";
import { fetchWithAuth } from "../../utils/fetchWithAuth";
import CommonFormModal from "../../components/CommonFormModel";
import MessageModal from "../../components/MessageModal";
import UserTable from "./UserMgmt/UserTable.js";
import axiosApi from "../../utils/axiosApi.js";

const userInstructions = [
      "Search users using available filters and search text.",
      "Use Change Password to update user credentials.",
      "Use Change Role to assign a new role to a user.",
      "Activate or Deactivate users as required.",
      "All updates require confirmation before saving.",
      "Changes take effect immediately after successful update."
];   

function UserManagement({ setModuleName }) {
   const navigate = useNavigate();  
   const [headNoRecord, setHeadNoRecord] = useState(false);
   const [searchText, setSearchText] = useState("");
   const [searchofficelevels, setSearchOfficeLevels] = useState([]);
   const [selectedsearchOfficeLevel, setSelectedSearchOfficeLevel] = useState("");
   const [searchofficeid, setSearchOfficeID] = useState([]);
   const [selectedSearchOfficeID, setSelectedSearchOfficeID] = useState("");
   const [searchroles, setSearchRoles] = useState([]);
   const [selectedSearchRoles, setSelectedSearchRoles] = useState("");
   const [searchstatus, setSearchStatus] = useState([]);
   const [selectedSearchStatus, setSelectedSearchStatus] = useState("");
   const [officelevels, setOfficeLevels] = useState([]);
   const [selectedOfficeLevel, setSelectedOfficeLevel] = useState("");
   const [offices, setOffice] = useState([]);
   const [selectedOffice, setSelectedOffice] = useState("");
   const [employees, setEmployees] = useState([]);
   const [newPassword, setNewPassword] = useState("");
   const [confirmPassword, setConfirmPassword] = useState("");
   const [currentRole, setCurrentRole] = useState("");
   const [selectedRole, setSelectedRole] = useState("");
   const [selectedUser, setSelectedUser] = useState("");
   const [selectedDesignation, setSelectedDesignation] = useState("");
   const [roles, setRoles] = useState([]);

   const [messageModal, setMessageModal] = useState({ show: false, title: "", message: "", type: "success",isConfirmation: false, onConfirm: null,});

   const [employee, setEmployee] = useState({ user_id:0,role_id:0,role_name:"",emp_code: "",title_id:0, emp_name: "",emp_name_local:"",
      mobile_no1: "", mobile_no2: "", email_id: "", office_level_id:0, office_id: "",office_level_name:"", office_name:"", desig_id:0,
      desig_name:"",action: "S", status: "A",});
  
   const cards =  useMemo(() =>[
   { title: "Total Users",count:employees[0]?.tot_users  || 0,  bgColor: "#eff6ff", iconColor: "#1d4ed8", icon: "fa fa-user" },
   { title: "Active",count:employees[0]?.tot_active   || 0,  bgColor: "#f0fdf4", iconColor: "#16a34a", icon: "fa fa-user" },
   { title: "Inactive",count:employees[0]?.tot_deactive   || 0,  bgColor: "#fffbeb", iconColor: "#d97706", icon: "fa fa-user" },   
   ], [employee]);

   useEffect(() => {
      setModuleName("User Management");
      setHeadNoRecord(true);
      fetchData("/user/get-roles", setRoles),
      fetchData("/user/get-officelevel", setOfficeLevels),
      loadUsersList();
   }, []);
   
   const fetchData = async (url, setter) => {
         try {
            const response = await axiosApi.get(url);
            setter(response.data);
         } catch (err) {
            console.error(err);
         }
   };
   const loadOffice = async (OfficeLevelID) => {
      try {
         const response = await axiosApi.post(`/user/get-dropdownoffice`,{office_level_id: Number(OfficeLevelID),});
         const data = await response.data;
         setOffice(data);
         setSearchOfficeID(data);
      } catch (err) {
         console.log(err);
      }
      };
   
   const loadUsersList = async (officeLevelID = "", officeID = "",RoleID="",status="",searchtxt="") => {
      console.log("Loading users with filters:", { officeLevelID, officeID, RoleID, status, searchtxt });
      try {
         const response = await fetchWithAuth(`/user/get-userslist`,
            {
            method: "POST", 
            body: JSON.stringify({ office_level_id: officeLevelID ? Number(officeLevelID): 0, office_id: officeID || "",role_id: RoleID ? Number(RoleID): 0 || 0,status: status || "",search_text: searchtxt||"",
            }),
            }, navigate
         );
         const data = await response.json();
         const employeeList = Array.isArray(data) ? data : [];
         console.log("employeeList:", employeeList);
         setEmployees(employeeList);
         console.log(employeeList.length);
         if (employeeList.length === 0) {
            setHeadNoRecord(true);
         } else {
            setHeadNoRecord(false);
         }

      } catch (err) {
         console.log(err);
         setHeadNoRecord(true);
      }
   };   
   const searchOffice = () => {
      let filtered = [...employee];
      if (selectedsearchOfficeLevel !== "") {
      filtered = filtered.filter(
      (item) =>
      String(item.office_level_id) ===
      String(selectedsearchOfficeLevel)
      );
      }
      if (selectedSearchOfficeID !== "") {filtered = filtered.filter((item) => String(item.office_id) === String(selectedSearchOfficeID));
      }
      if (selectedSearchStatus !== "") {filtered = filtered.filter((item) => String(item.status) === String(selectedSearchStatus));
      }
      if (selectedSearchRoles !== "") {filtered = filtered.filter((item) => String(item.role_id) === String(selectedSearchRoles));
      }
      if (searchText.trim() !== "") { const text = searchText.toLowerCase();
      filtered = filtered.filter(
         (item) => item.emp_name?.toLowerCase().includes(text) || item.emp_code?.toLowerCase().includes(text) || item.office_name?.toLowerCase().includes(text)
      );
      }
      setEmployees(filtered);
   };
   const resetFilter = () => {
   setSelectedSearchOfficeLevel("");
   setSelectedSearchOfficeID("");
   setSelectedSearchStatus("");
   setSelectedSearchRoles("");
   setSearchText("");
   setSearchOfficeID([]);
   loadUsersList("", "");
   };

   const handleUpdateStatus = (user, action) => {

   let message = "";

   switch (action) {
      case "R":
         message = "Are you sure you want to change role?";
         break;

      case "P":
         message = "Are you sure you want to change password?";
         break;

      case "A":
         message = "Are you sure you want to activate user?";
         break;

      case "D":
         message = "Are you sure you want to deactivate user?";
         break;

      default:
         message = "Are you sure?";
   }

   setMessageModal({ show: true, title: "Confirmation", message, type: "warning", isConfirmation: true, onConfirm: () => updateUserStatus(user, action), });
};
const updateUserStatus = async (user, action) => {
   try {
      console.log("Selected Role:", selectedRole);

      const updateUser = {
         emp_id: user.emp_id,
         user_id: user.user_id,
         role_id: Number(selectedRole),
         action,
         status: action,
         ...(action === "P" && { password: newPassword })
      };

      console.log("Update Payload:", updateUser);

      const response = await fetchWithAuth(`/user/updateuser`,
         {
            method: "POST",
            body: JSON.stringify(updateUser),
         },
         navigate
      );

      const data = await response.json();

      if (response.ok) {
         // Clear form
   setNewPassword("");
   setConfirmPassword("");
   setSelectedRole("");
   setCurrentRole("");
   setSelectedUser("");
   setSelectedOffice("");
   setSelectedDesignation("");

   // Close Role Modal
   const roleModalEl = document.getElementById("changeRoleModal");
   const roleModal = bootstrap.Modal.getInstance(roleModalEl);
   if (roleModal) roleModal.hide();

   // Close Password Modal
   const passwordModalEl = document.getElementById("changePasswordModal");
   const passwordModal = bootstrap.Modal.getInstance(passwordModalEl);
   if (passwordModal) passwordModal.hide();

   // Success Message
   let successMessage = "";

   switch (action) {
      case "R":
         successMessage = "User role updated successfully.";
         break;
      case "P":
         successMessage = "User password updated successfully.";
         break;
      case "A":
         successMessage = "User activated successfully.";
         break;
      case "D":
         successMessage = "User deactivated successfully.";
         break;
      default:
         successMessage = "Operation completed successfully.";
   }
   setMessageModal({ show: true, title: "Success", message: successMessage, type: "success", isConfirmation: false, onConfirm: null, });
   loadUsersList();

      } else {
         setMessageModal({ show: true, title: "Message", message: "Update failed", type: "success", isConfirmation: false, onConfirm: null, });
      }
   } catch (err) {
      console.error(err);
      setMessageModal({ show: true, title: "Message", message: "Error while updating user status.", type: "success", isConfirmation: false, onConfirm: null, });
   }
};
   const handleChangeRoleClick = (user) => {
      setEmployee(user);
      setCurrentRole(user.role_name);
      setSelectedRole(user.role_id);
      setSelectedUser(user.emp_code + " - " + user.emp_name);
      setSelectedOffice(user.office_name);
      setSelectedDesignation(user.desig_name);
   };
  return (
      <div className="container-fluid content-inner mt-n5 px-3 py-0">
         <div className="row g-3 py-3">
            <div className="col-xl-2 col-lg-4">
               {cards.map((card, index) => (
               <SummaryCard key={index} {...card} />
               ))}
               <CommonInstructions title="Instructions" instructions={userInstructions} /> 
            </div>
      <div className="col-xl-10 col-lg-10">
         <div className="card">
            <div className="card-header border-0">
               <div className="d-flex justify-content-between align-items-center mb-2">
               <div className="header-title">
               <h5 className="card-title mb-0">Users List</h5>
               </div>
               </div>
               <div className="d-flex flex-nowrap gap-2 align-items-center w-100">
                  {/* Office Level Dropdown */}
                  <div className="flex-fill">
                     <select id="drpSearchOfcLevel" className="form-select form-select-sm" value={selectedsearchOfficeLevel} onChange={(e) => {
                     const OfficeLevelID = e.target.value; setSelectedSearchOfficeLevel(OfficeLevelID); loadOffice(OfficeLevelID); setSelectedSearchOfficeID("");}} >
                     <option value="">Select Office Level</option>
                     {officelevels.map((level) => (
                     <option key={level.office_level_id} value={level.office_level_id}>
                     {level.office_level_name}
                     </option>
                     ))}
                     </select>
                  </div>
                  {/* Office Dropdown */}
                  <div className="flex-fill">
                     <select id="drpSearchOfcID" className="form-select form-select-sm" value={selectedSearchOfficeID} onChange={(e) => { setSelectedSearchOfficeID(e.target.value); }} >
                     <option value="">Select Office</option>
                     {searchofficeid.map((office) => (
                     <option key={office.office_id} value={office.office_id} >
                     {office.office_name}
                     </option>
                     ))}
                     </select>
                  </div>
                  {/* Office Dropdown */}
                  <div className="flex-fill">
                     <select id="drpSearchRole" className="form-select form-select-sm" value={selectedSearchRoles} onChange={(e) => { setSelectedSearchRoles(e.target.value); }} >
                     <option value="">Select Role</option>
                     {searchroles.map((role) => (
                     <option key={role.role_id} value={role.role_id}>
                     {role.role_name}
                     </option>
                     ))}
                     </select>
                  </div>
                  <div className="flex-fill">
                     <select id="drpSearchStatus" className="form-select form-select-sm" value={selectedSearchStatus} onChange={(e) => { setSelectedSearchStatus(e.target.value); }} >
                     <option value="">Select Status</option>
                     <option value={`A`}>Active</option>
                     <option value={`D`}>Deactive</option>
                     </select>
                  </div>
                  <div className="flex-fill">
                     <input type="text" className={`form-control form-control-sm `} id="tbsearch"
                     placeholder="Search Text Here" value={searchText} onChange={(e) => setSearchText(e.target.value)} />
                     </div>

                     {/* Buttons */}
                     <div className="flex-shrink-0">
                     <button className="btn btn-primary btn-sm" type="button" data-bs-toggle="tooltip" data-bs-placement="top" data-bs-custom-class="white-tooltip" data-bs-title="Search" onClick={() => loadUsersList( selectedsearchOfficeLevel, selectedSearchOfficeID, selectedSearchRoles, selectedSearchStatus, searchText )} >
                     <i className="fa fa-search text-white"></i>&nbsp;
                     </button>
                     &nbsp;
                     <button className="btn btn-danger btn-sm" type="button" data-bs-toggle="tooltip" data-bs-placement="top" data-bs-custom-class="white-tooltip" data-bs-title="Reset" onClick={resetFilter} >
                     <i className="fa fa-refresh text-white"></i>&nbsp;
                     </button>
                  </div>

               </div>
            </div>
            <div className="card-body">
               <CommonTable data={employees} columns={columns}  rowsPerPage={10} renderActions={(b) => (<>
               <button className="btn btn-sm btn-icon btn-warning" title="Change Password" data-bs-toggle="modal"
               data-bs-target="#changePasswordModal" onClick={() => handleChangeRoleClick(b)}>
               <i className="fa fa-key text-white"></i>
               </button>
               <button className="btn btn-sm btn-icon btn-primary" title="Change Role"  data-bs-toggle="modal"
               data-bs-target="#changeRoleModal" onClick={() => handleChangeRoleClick(b)}>
               <i className="fa fa-tasks text-white"></i>
               </button>

               {b.status === "A" ? (
               <button className="btn btn-sm btn-icon btn-danger" title="Deactivate" onClick={() => handleUpdateStatus(b, "D")} >
               <i className="fa fa-toggle-on text-white"></i>
               </button>
               ) : (
               <button className="btn btn-sm btn-icon btn-success" title="Activate" onClick={() => handleUpdateStatus(b, "A")} >
               <i className="fa fa-toggle-off text-white"></i>
               </button>
               )}
               </>
               )}
               />
            </div>
         </div>
      </div>
      <div className="col-xl-5 col-lg-6">        
      </div>
      </div>
      <CommonFormModal modalId="changePasswordModal" title="Change Password" onSave={() => handleUpdateStatus(employee, "P")} saveText="Update Password">
         <div className="row">      
            {/* Password Policy - Left */}
            <div className="col-md-12">
               <div className="mb-3 text-center">
                  <label className="form-label col-form-label col-form-label-sm text-danger">You are changing the password for &nbsp;
                  <strong>{selectedUser}</strong></label>
               </div></div>
            <div className="col-md-6 border-end">
               <div className="h-100">
                  <h6 className="fw-bold text-primary mb-3">
                     <i className="fa fa-shield-alt me-2"></i>
                     Password Policy
                  </h6>
                  <ol className="small ps-3">
                     <li>Minimum 8 characters.</li>
                     <li>At least one uppercase letter (A-Z).</li>
                     <li>At least one lowercase letter (a-z).</li>
                     <li>At least one numeric digit (0-9).</li>
                     <li>At least one special character.</li>
                     <li>Must not contain spaces.</li>
                     <li>Must not be the same as the previous password.</li>
                  </ol>
               </div>
            </div>
            {/* Form - Right */}
            <div className="col-md-6">
               <div className="mb-3">
                  <label className="form-label fw-semibold"> New Password </label>
                  <input type="password" className="form-control form-control-sm" value={newPassword} onChange={(e) => setNewPassword(e.target.value)} />
               </div>

               <div className="mb-3">
                  <label className="form-label fw-semibold"> Confirm Password </label>
                  <input type="password" className="form-control form-control-sm" value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} />
               </div>
            </div>

         </div>
      </CommonFormModal>

      <CommonFormModal modalId="changeRoleModal" title="Change Role" saveText="Update Role" onSave={() => handleUpdateStatus({  ...employee, role_id: selectedRole }, "R" ) } >
         <div className="row">
            <div className="col-md-6 border-end">
               <label className="form-label col-form-label col-form-label-sm">You are changing the role for<br />
                  <strong className="text-dark">{selectedUser}</strong></label>
                  <label className="form-label col-form-label col-form-label-sm p-0">Designation <strong>{selectedDesignation}</strong></label>
                  <label className="form-label col-form-label col-form-label-sm p-0">Office <strong>{selectedOffice}</strong></label><br />
                  <label className="form-label col-form-label col-form-label-sm p-0">Current Role <strong>{currentRole}</strong></label>
            </div>
            <div className="col-md-6">      
                  <label className="form-label col-form-label col-form-label-sm">Select New Role</label>
                  <select className="selectpicker form-select form-select-sm" value={selectedRole} onChange={(e) => setSelectedRole(e.target.value)} >
                     <option value="">Select Role</option>
                     {roles.map((role) => (
                     <option key={role.role_id} value={role.role_id}>
                        {role.role_name}
                     </option>
                     ))}
                  </select>
         </div>
         </div>
      </CommonFormModal>

      <MessageModal show={messageModal.show} title={messageModal.title} message={messageModal.message} type={messageModal.type}
         isConfirmation={messageModal.isConfirmation} onConfirm={messageModal.onConfirm} 
         onClose={() => setMessageModal((prev) => ({ ...prev, show: false, })) } />

   </div>
 );
}

export default UserManagement;
